%[text] # 例7.7（低ランク近似）
%[text] 村松正吾　「多次元信号・画像処理の基礎と展開」
%[text] 動作確認： MATLAB R2026a
%[text] ## 準備
prj = matlab.project.currentProject;
prjroot = prj.RootFolder;
datfolder = fullfile(prjroot,"data");
resfolder = fullfile(prjroot,"results");
myfilename = "example07_07"; % mfilename

imgname = "msipimg05";
imgfmt = "tiff";

close all

%%
%[text] ## 画像データの読込
imgfile = fullfile(datfolder,imgname);
X = imresize(im2double(rgb2gray(imread(imgfile,imgfmt))),[96 96],'bilinear');

figure(1) %[output:229319d8]
subplot(1,3,1) %[output:229319d8]
imshow(X) %[output:229319d8]
title('原画像') %[output:229319d8]
%imwrite(X,fullfile(resfolder,myfilename+"org"),imgfmt)

% GPUに転送
%X = gpuArray(X);
%%
%[text] ## 特異値分解
[U,S,V] = svd(X,"econ");
sigmas = diag(S) %[output:7c2cd3b3]
figure(2) %[output:0d76af7e]
hp = plot(0:numel(sigmas)-1,sigmas); %[output:0d76af7e]
hp.LineWidth = 1; %[output:0d76af7e]
hp.Color = [.1 .1 .1]; %[output:0d76af7e]
hp.Marker = "o"; %[output:0d76af7e]
hp.MarkerFaceColor = [.8 .8 .8]; %[output:0d76af7e]
hp.MarkerEdgeColor = [.1 .1 .1]; %[output:0d76af7e]
hp.MarkerSize = 4; %[output:0d76af7e]
grid on %[output:0d76af7e]
axis square %[output:0d76af7e]
xlabel("$k$","Interpreter","latex") %[output:0d76af7e]
ylabel("$\sigma_k$","Interpreter","latex") %[output:0d76af7e]
axis([0 95 0 50]) %[output:0d76af7e]
ax = gca;
ax.FontSize = 12; %[output:0d76af7e]
ax.LineWidth = 1; %[output:0d76af7e]

exportgraphics(ax,fullfile(resfolder,"fig07-11a.png")) %[output:0d76af7e]
%%
%[text] ## 1-ランク近似
r = 1;

Xaprx = U(:,1:r)*diag(sigmas(1:r))*V(:,1:r)';

figure(1)
subplot(1,3,2) %[output:5862dee6]
imshow(Xaprx) %[output:5862dee6]
title(num2str(r)+"-ランク近似 PSNR: " + num2str(psnr(X,Xaprx)) + " dB") %[output:5862dee6]
imwrite(Xaprx,fullfile(resfolder,"fig07-11b.png"))
%%
%[text] ## ランク-10近似
r = 10;

Xaprx = U(:,1:r)*diag(sigmas(1:r))*V(:,1:r)';

figure(1)
subplot(1,3,3) %[output:0b1564f8]
imshow(Xaprx) %[output:0b1564f8]
title(num2str(r)+"-ランク近似 PSNR: " + num2str(psnr(X,Xaprx)) + " dB") %[output:0b1564f8]
imwrite(X20,fullfile(resfolder,"fig07-11c.png"))
%%
